  const CanId send_id{};
  sender_->send(send_msg, send_id, send_timeout_);
  {
    uint32_t receive_msg{};
    CanId receive_id{};
    EXPECT_NO_THROW(receive_id = receiver_->receive(receive_msg, receive_timeout_));
