  /// Sets bit 31 to 1
  CanId & extended() noexcept;
  /// Sets bit 29 to 1, and bit 30 to 0
  CanId & error_frame() noexcept;
  /// Sets bit 29 to 0, and bit 30 to 1
  CanId & remote_frame() noexcept;
