class ROS2Parser
{
public:
#define TAM_TSL_PRINT_ENUM_MEMBER(dtype, typename) ENUM_##typename
  enum DTYPE_ENUM {
    TAM_TSL_FOR_EVERY_SUPPORTED_PRIMITIVE_DATATYPE_WITH_SEPARATOR(
      TAM_TSL_PRINT_ENUM_MEMBER, TAM_TSL_COMMA)
  };
