  ASSERT_FLOAT_EQ(normalize_angle(-1.5 * M_PI), 0.5 * M_PI);
  ASSERT_FLOAT_EQ(normalize_angle(-2 * M_PI), 0 * M_PI);
  ASSERT_FLOAT_EQ(normalize_angle(2.5 * M_PI), 0.5 * M_PI);
  ASSERT_FLOAT_EQ(normalize_angle(10.5 * M_PI), 0.5 * M_PI);
}
