          std::cout << "[VehicleHandler]: Set parameter " << param << " in your module" \
            << std::endl;                                                               \
          continue;                                                                     \
        }
      FOR_EVERY_SUPPORTED_PARAM_TYPE(SET_MODULE_PARAM);
      #undef SET_MODULE_PARAM
      // clang-format on
    }
  }
